type TreeCellMode int64 //gd:TreeItem.TreeCellMode

const (
	// Cell shows a string label, optionally with an icon. When editable, the text can be edited using a [LineEdit], or a [TextEdit] popup if [SetEditMultiline] is used.
	//
	// [LineEdit]: https://pkg.go.dev/graphics.gd/classdb/LineEdit
	// [SetEditMultiline]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetEditMultiline
	// [TextEdit]: https://pkg.go.dev/graphics.gd/classdb/TextEdit
	CellModeString TreeCellMode = 0
	// Cell shows a checkbox, optionally with text and an icon. The checkbox can be pressed, released, or indeterminate (via [SetIndeterminate]). The checkbox can't be clicked unless the cell is editable.
	//
	// [SetIndeterminate]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetIndeterminate
	CellModeCheck TreeCellMode = 1
	// Cell shows a numeric range. When editable, it can be edited using a range slider. Use [SetRange] to set the value and [SetRangeConfig] to configure the range.
	//
	// This cell can also be used in a text dropdown mode when you assign a text with [SetText]. Separate options with a comma, e.g. "Option1,Option2,Option3".
	//
	// [SetRange]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetRange
	// [SetRangeConfig]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetRangeConfig
	// [SetText]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetText
	CellModeRange TreeCellMode = 2
	// Cell shows an icon. It can't be edited nor display text. The icon is always centered within the cell.
	CellModeIcon TreeCellMode = 3
	// Cell shows as a clickable button. It will display an arrow similar to [OptionButton], but doesn't feature a dropdown (for that you can use [CellModeRange]). Clicking the button emits the [OnTree.ItemEdited] signal. The button is flat by default, you can use [SetCustomAsButton] to display it with a [StyleBox].
	//
	// This mode also supports custom drawing using [SetCustomDrawCallback].
	//
	// [OnTree.ItemEdited]: https://pkg.go.dev/graphics.gd/classdb/#Instance.OnTree.ItemEdited
	// [OptionButton]: https://pkg.go.dev/graphics.gd/classdb/OptionButton
	// [SetCustomAsButton]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetCustomAsButton
	// [SetCustomDrawCallback]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetCustomDrawCallback
	// [StyleBox]: https://pkg.go.dev/graphics.gd/classdb/StyleBox
	CellModeCustom TreeCellMode = 4
)

type RangeConfig struct {
	Min  float32 `gd:"min"`
	Max  float32 `gd:"max"`
	Step float32 `gd:"step"`
	Expr string  `gd:"expr"`
}
